import{_ as e,o,c as t,a5 as r}from"./chunks/framework.B5tqjWbr.js";const P=JSON.parse('{"title":"概念：PCS 并网跟随型 P/Q 控制","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：PCS 并网跟随型 P/Q 控制","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0043-pcs-grid-following-pq-control.html` 的源稿。"},"headers":[],"relativePath":"content/power/concepts/pcs/grid-following-pq-control.md","filePath":"content/power/concepts/pcs/grid-following-pq-control.md","lastUpdated":null}'),i={name:"content/power/concepts/pcs/grid-following-pq-control.md"};function l(n,a,s,c,p,d){return o(),t("div",null,[...a[0]||(a[0]=[r(`<h1 id="概念-pcs-并网跟随型-p-q-控制" tabindex="-1">概念：PCS 并网跟随型 P/Q 控制 <a class="header-anchor" href="#概念-pcs-并网跟随型-p-q-控制" aria-label="Permalink to &quot;概念：PCS 并网跟随型 P/Q 控制&quot;">​</a></h1><p>本页是 <code>lessons/0043-pcs-grid-following-pq-control.html</code> 的源稿。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>储能变流器（power conversion system / PCS）连接电池和电网。并网跟随型控制（grid-following control / GFL）用 PLL 跟随电网，有功无功控制（active and reactive power control / P/Q control）生成 id/iq 电流参考。</p><h2 id="为什么-ups-pcs-需要它" tabindex="-1">为什么 UPS/PCS 需要它 <a class="header-anchor" href="#为什么-ups-pcs-需要它" aria-label="Permalink to &quot;为什么 UPS/PCS 需要它&quot;">​</a></h2><p>UPS 的三相 PLL、电流环、SVPWM 和状态机可迁移到 PCS。PCS 进一步加入充放电功率调度和电网交互。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>id_ref = 2 * P_ref / (3 * Vd)</span></span>
<span class="line"><span>iq_ref = -2 * Q_ref / (3 * Vd)</span></span></code></pre></div><h2 id="一个仿真任务" tabindex="-1">一个仿真任务 <a class="header-anchor" href="#一个仿真任务" aria-label="Permalink to &quot;一个仿真任务&quot;">​</a></h2><p>让 P_ref 和 Q_ref 分别阶跃，观察 id/iq 和 P/Q 的跟随。</p><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能解释 GFL 为什么依赖 PLL。</li><li>能把 P/Q 指令转换为 id/iq 指令。</li><li>能说明充电和放电的功率方向约定。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><p>PCS 中 P/Q 限幅通常在指令层、外环还是状态机中处理？</p>`,14)])])}const u=e(i,[["render",l]]);export{P as __pageData,u as default};
